 float UiScale()=>Mathf.Clamp(Mathf.Min(Screen.width/1280f,Screen.height/720f),1f,1.35f);
 int Fs(float pixels)=>Mathf.RoundToInt(pixels*UiScale());
 float Us(float pixels)=>pixels*UiScale();
 void ApplyBookTypography(){if(!BookUiActive())return;header.fontSize=Fs(24);header.fontStyle=FontStyle.Bold;body.fontSize=Fs(18);body.fontStyle=FontStyle.Bold;button.fontSize=Fs(19);button.fontStyle=FontStyle.Bold;card.fontSize=Fs(17);screenSubtitle.fontSize=Fs(17);screenSubtitle.fontStyle=FontStyle.Bold;navButton.fontSize=Fs(16);navSelected.fontSize=Fs(16);badge.fontSize=Fs(14);hubLabel.fontSize=Fs(17);hubLabelHover.fontSize=Fs(17);}
